// // This is a 32-to-5 decoder that maps a 32-bit input to a 5-bit output
module decoder5to32 (
    input [4:0] A,
    output reg [31:0] Y
);
    always @(*) begin
        Y = 32'b0; // Initialize output to all zeros
        Y[A] = 1'b1; // Set the corresponding output bit
    end
endmodule
